// Type aliases vs. Interfaces
type Id = number | string;

interface User {
  name: string;
}

type NamedUser = User & { id: Id };

let user: NamedUser = {
  id: 1,
  name: 'Alice'
};

console.log(user); // { id: 1, name: 'Alice' }
// let invalid: NamedUser = { name: 'Bob' }; // Error: property 'id' is missing

// Type aliases with union types
type Status = 'active' | 'inactive' | 'pending';

let currentStatus: Status = 'active';
console.log(currentStatus); // active
currentStatus = 'pending';
console.log(currentStatus); // pending
// currentStatus = 'failed'; // Error: 'failed' cannot be assigned to Status

// Type aliases with intersection types
type Contact = {
  email: string;
};

type Profile = {
  username: string;
};

type User = Contact & Profile;

let user: User = {
  email: 'alice@example.com',
  username: 'alice123'
};

console.log(user); // { email: 'alice@example.com', username: 'alice123' }
// let invalid: User = { email: 'bob@example.com' }; // Error: username is missing

// Type aliases in functions
type User = {
  id: number;
  name: string;
};

function printUser(user: User): string {
  return `ID: ${user.id}, Name: ${user.name}`;
}

let user: User = { id: 1, name: 'Alice' };
console.log(printUser(user)); // ID: 1, Name: Alice
// let invalid: User = { id: 2 }; // Error: name is missing

// Type aliases in objects
type Product = {
  id: number;
  name: string;
  price: number;
};

let product: Product = {
  id: 1,
  name: 'Laptop',
  price: 1000
};

console.log(product); // { id: 1, name: 'Laptop', price: 1000 }
// let invalid: Product = { id: 2, name: 'Phone' }; // Error: price is missing

// Practical example
type Order = {
  id: number;
  status: 'pending' | 'shipped' | 'delivered';
};

function getOrderInfo(order: Order): string {
  return `Order ${order.id} is ${order.status}`;
}

let order: Order = { id: 1, status: 'pending' };
console.log(getOrderInfo(order)); // Order 1 is pending
order.status = 'delivered';
console.log(getOrderInfo(order)); // Order 1 is delivered
// order.status = 'cancelled'; // Error: 'cancelled' cannot be assigned to status

// Security example
type Admin = {
  name: string;
  role: 'admin';
};

function getAdminInfo(admin: Admin): string {
  return `${admin.name} is ${admin.role}`;
}

let admin: Admin = { name: 'Alice', role: 'admin' };
console.log(getAdminInfo(admin)); // Alice is admin
// let invalid: Admin = { name: 'Bob' }; // Error: role is missing

// Error-prone example
let unsafe: any = { name: 'Alice', role: 'admin' };
console.log(unsafe.name, unsafe.role); // Alice, admin, but no type safety
unsafe = { name: 'Bob' };
console.log(unsafe.name, unsafe.role); // Bob, undefined, may cause runtime errors

// Correct approach
type User = {
  name: string;
  role: string;
};
let user: User = { name: 'Alice', role: 'admin' };
console.log(user.name, user.role); // Alice, admin
// let invalid: User = { name: 'Bob' }; // Error: role is missing

// Real-world scenario
type Product = {
  id: number;
  name: string;
  price: number;
};

type DiscountedProduct = Product & { discount: number };

function calculateFinalPrice(product: DiscountedProduct): number {
  return product.price * product.discount;
}

let product: DiscountedProduct = {
  id: 1,
  name: 'Phone',
  price: 1000,
  discount: 0.9
};

console.log(calculateFinalPrice(product)); // 900

