// Псевдонимы типов против интерфейсов
type Id = number | string;

interface User {
  name: string;
}

type NamedUser = User & { id: Id };

let user: NamedUser = {
  id: 1,
  name: 'Алиса'
};

console.log(user); // { id: 1, name: 'Алиса' }
// let invalid: NamedUser = { name: 'Боб' }; // Ошибка: отсутствует свойство 'id'

// Псевдонимы типов с типами объединения
type Status = 'active' | 'inactive' | 'pending';

let currentStatus: Status = 'active';
console.log(currentStatus); // active
currentStatus = 'pending';
console.log(currentStatus); // pending
// currentStatus = 'failed'; // Ошибка: 'failed' не может быть присвоен Status

// Псевдонимы типов с типами пересечения
type Contact = {
  email: string;
};

type Profile = {
  username: string;
};

type User = Contact & Profile;

let user: User = {
  email: 'alice@example.com',
  username: 'alice123'
};

console.log(user); // { email: 'alice@example.com', username: 'alice123' }
// let invalid: User = { email: 'bob@example.com' }; // Ошибка: отсутствует username

// Псевдонимы типов в функциях
type User = {
  id: number;
  name: string;
};

function printUser(user: User): string {
  return `ID: ${user.id}, Имя: ${user.name}`;
}

let user: User = { id: 1, name: 'Алиса' };
console.log(printUser(user)); // ID: 1, Имя: Алиса
// let invalid: User = { id: 2 }; // Ошибка: отсутствует name

// Псевдонимы типов в объектах
type Product = {
  id: number;
  name: string;
  price: number;
};

let product: Product = {
  id: 1,
  name: 'Ноутбук',
  price: 1000
};

console.log(product); // { id: 1, name: 'Ноутбук', price: 1000 }
// let invalid: Product = { id: 2, name: 'Телефон' }; // Ошибка: отсутствует price

// Практический пример
type Order = {
  id: number;
  status: 'pending' | 'shipped' | 'delivered';
};

function getOrderInfo(order: Order): string {
  return `Заказ ${order.id} имеет статус ${order.status}`;
}

let order: Order = { id: 1, status: 'pending' };
console.log(getOrderInfo(order)); // Заказ 1 имеет статус pending
order.status = 'delivered';
console.log(getOrderInfo(order)); // Заказ 1 имеет статус delivered
// order.status = 'cancelled'; // Ошибка: 'cancelled' не может быть присвоен status

// Пример безопасности
type Admin = {
  name: string;
  role: 'admin';
};

function getAdminInfo(admin: Admin): string {
  return `${admin.name} является ${admin.role}`;
}

let admin: Admin = { name: 'Алиса', role: 'admin' };
console.log(getAdminInfo(admin)); // Алиса является admin
// let invalid: Admin = { name: 'Боб' }; // Ошибка: отсутствует role

// Пример, вызывающий ошибку
let unsafe: any = { name: 'Алиса', role: 'admin' };
console.log(unsafe.name, unsafe.role); // Алиса, admin, но без безопасности типов
unsafe = { name: 'Боб' };
console.log(unsafe.name, unsafe.role); // Боб, undefined, может вызвать ошибки во время выполнения

// Правильный подход
type User = {
  name: string;
  role: string;
};
let user: User = { name: 'Алиса', role: 'admin' };
console.log(user.name, user.role); // Алиса, admin
// let invalid: User = { name: 'Боб' }; // Ошибка: отсутствует role

// Реальный сценарий
type Product = {
  id: number;
  name: string;
  price: number;
};

type DiscountedProduct = Product & { discount: number };

function calculateFinalPrice(product: DiscountedProduct): number {
  return product.price * product.discount;
}

let product: DiscountedProduct = {
  id: 1,
  name: 'Телефон',
  price: 1000,
  discount: 0.9
};

console.log(calculateFinalPrice(product)); // 900

